import{_ as o,c as e,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"다중 채널 및 플랫폼 | Clawdbot 튜토리얼","description":"WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS 및 Android 플랫폼을 포함하여 Clawdbot의 다중 채널 시스템을 구성하고 사용하는 방법을 학습하세요.","frontmatter":{"title":"다중 채널 및 플랫폼 | Clawdbot 튜토리얼","sidebarTitle":"일반적으로 사용되는 채팅 도구 연결","subtitle":"다중 채널 및 플랫폼","description":"WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS 및 Android 플랫폼을 포함하여 Clawdbot의 다중 채널 시스템을 구성하고 사용하는 방법을 학습하세요.","tags":["channels","platforms","integration"],"order":60},"headers":[],"relativePath":"ko/moltbot/moltbot/platforms/index.md","filePath":"ko/moltbot/moltbot/platforms/index.md"}'),r={name:"ko/moltbot/moltbot/platforms/index.md"};function i(s,a,n,h,d,g){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="다중-채널-및-플랫폼" tabindex="-1">다중 채널 및 플랫폼 <a class="header-anchor" href="#다중-채널-및-플랫폼" aria-label="Permalink to &quot;다중 채널 및 플랫폼&quot;">​</a></h1><p>Clawdbot은 통합된 Gateway 제어 평면을 통해 다양한 통신 채널과 플랫폼을 지원하므로, 익숙한 인터페이스에서 AI 어시스턴트와 상호 작용할 수 있습니다.</p><h2 id="장-개요" tabindex="-1">장 개요 <a class="header-anchor" href="#장-개요" aria-label="Permalink to &quot;장 개요&quot;">​</a></h2><p>이 장에서는 Clawdbot이 지원하는 모든 통신 채널과 플랫폼을 소개합니다. 여기에는 인스턴트 메시징 앱(WhatsApp, Telegram, Slack, Discord 등), 모바일 노드(iOS, Android) 및 데스크톱 애플리케이션(macOS)이 포함됩니다. 이러한 채널을 구성하여 AI 어시스턴트를 일상적인 업무 흐름에 매끄럽게 통합하는 방법을 알아보세요.</p><h2 id="하위-페이지-탐색" tabindex="-1">하위 페이지 탐색 <a class="header-anchor" href="#하위-페이지-탐색" aria-label="Permalink to &quot;하위 페이지 탐색&quot;">​</a></h2><h3 id="채널-개요" tabindex="-1">채널 개요 <a class="header-anchor" href="#채널-개요" aria-label="Permalink to &quot;채널 개요&quot;">​</a></h3><ul><li><strong><a href="./channels-overview/">다중 채널 시스템 개요</a></strong> - Clawdbot이 지원하는 모든 통신 채널과 그 특징을 알아보고 채널 구성의 기본 개념을 파악하세요.</li></ul><h3 id="인스턴트-메시징-채널" tabindex="-1">인스턴트 메시징 채널 <a class="header-anchor" href="#인스턴트-메시징-채널" aria-label="Permalink to &quot;인스턴트 메시징 채널&quot;">​</a></h3><ul><li><strong><a href="./whatsapp/">WhatsApp</a></strong> - WhatsApp 채널 구성 및 사용(Baileys 기반), 기기 연결 및 그룹 관리 지원.</li><li><strong><a href="./telegram/">Telegram</a></strong> - Telegram 채널 구성 및 사용(grammY Bot API 기반), Bot Token 및 Webhook 설정.</li><li><strong><a href="./slack/">Slack</a></strong> - Slack 채널 구성 및 사용(Bolt 기반), 작업 공간에 통합.</li><li><strong><a href="./discord/">Discord</a></strong> - Discord 채널 구성 및 사용(discord.js 기반), 서버 및 채널 지원.</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Google Chat 채널 구성 및 사용, Google Workspace와 통합.</li><li><strong><a href="./signal/">Signal</a></strong> - Signal 채널 구성 및 사용(signal-cli 기반), 프라이버시 보호 통신.</li><li><strong><a href="./imessage/">iMessage</a></strong> - iMessage 채널 구성 및 사용(macOS 전용), macOS 메시지 앱과 통합.</li><li><strong><a href="./line/">LINE</a></strong> - LINE 채널 구성 및 사용(Messaging API 기반), LINE 사용자와 상호 작용.</li></ul><h3 id="웹-및-네이티브-애플리케이션" tabindex="-1">웹 및 네이티브 애플리케이션 <a class="header-anchor" href="#웹-및-네이티브-애플리케이션" aria-label="Permalink to &quot;웹 및 네이티브 애플리케이션&quot;">​</a></h3><ul><li><strong><a href="./webchat/">WebChat 인터페이스</a></strong> - 내장된 WebChat 인터페이스를 사용하여 외부 채널 구성 없이 AI 어시스턴트와 상호 작용.</li><li><strong><a href="./macos-app/">macOS 애플리케이션</a></strong> - macOS 메뉴 바 애플리케이션의 기능인 Voice Wake, Talk Mode 및 원격 제어를 알아보세요.</li><li><strong><a href="./ios-node/">iOS 노드</a></strong> - 장치 로컬 작업(Camera, Canvas, Voice Wake)을 수행하도록 iOS 노드를 구성.</li><li><strong><a href="./android-node/">Android 노드</a></strong> - 장치 로컬 작업(Camera, Canvas)을 수행하도록 Android 노드를 구성.</li></ul><h2 id="학습-경로-추천" tabindex="-1">학습 경로 추천 <a class="header-anchor" href="#학습-경로-추천" aria-label="Permalink to &quot;학습 경로 추천&quot;">​</a></h2><p>사용 시나리오에 따라 다음과 같은 학습 순서를 추천합니다:</p><h3 id="초보자-빠른-시작" tabindex="-1">초보자 빠른 시작 <a class="header-anchor" href="#초보자-빠른-시작" aria-label="Permalink to &quot;초보자 빠른 시작&quot;">​</a></h3><p>Clawdbot을 처음 사용하는 경우 다음 순서대로 학습하는 것이 좋습니다:</p><ol><li><strong><a href="./channels-overview/">다중 채널 시스템 개요</a></strong> - 전체 아키텍처와 채널 개념 먼저 이해</li><li><strong><a href="./webchat/">WebChat 인터페이스</a></strong> - 구성 없이 바로 사용할 수 있는 가장 간단한 방법</li><li><strong>일반적으로 사용되는 채널 하나 선택</strong> - 일상적인 습관에 따라 선택: <ul><li>일상 채팅 → <a href="./whatsapp/">WhatsApp</a> 또는 <a href="./telegram/">Telegram</a></li><li>팀 협업 → <a href="./slack/">Slack</a> 또는 <a href="./discord/">Discord</a></li><li>macOS 사용자 → <a href="./imessage/">iMessage</a></li></ul></li></ol><h3 id="모바일-통합" tabindex="-1">모바일 통합 <a class="header-anchor" href="#모바일-통합" aria-label="Permalink to &quot;모바일 통합&quot;">​</a></h3><p>휴대폰에서 Clawdbot을 사용하려는 경우:</p><ol><li><strong><a href="./ios-node/">iOS 노드</a></strong> - iPhone/iPad에서 로컬 기능 구성</li><li><strong><a href="./android-node/">Android 노드</a></strong> - Android 장치에서 로컬 기능 구성</li><li><strong><a href="./macos-app/">macOS 애플리케이션</a></strong> - macOS 앱을 제어 센터로 사용</li></ol><h3 id="엔터프라이즈-배포" tabindex="-1">엔터프라이즈 배포 <a class="header-anchor" href="#엔터프라이즈-배포" aria-label="Permalink to &quot;엔터프라이즈 배포&quot;">​</a></h3><p>팀 환경에 배포해야 하는 경우:</p><ol><li><strong><a href="./slack/">Slack</a></strong> - 팀 작업 공간 통합</li><li><strong><a href="./discord/">Discord</a></strong> - 커뮤니티 서버 구축</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Google Workspace 통합</li></ol><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><p>이 장을 학습하기 전에 먼저 다음을 완료하는 것이 좋습니다:</p><ul><li><strong><a href="./../start/getting-started/">빠른 시작</a></strong> - Clawdbot 설치 및 기본 구성 완료</li><li><strong><a href="./../start/onboarding-wizard/">마법사 구성</a></strong> - 마법사를 통해 Gateway 및 채널의 기본 설정 완료</li></ul><div class="tip custom-block"><p class="custom-block-title">팁</p><p>마법사 구성을 완료한 경우 일부 채널이 이미 자동으로 구성되어 있을 수 있습니다. 중복되는 구성 단계를 건너뛰고 특정 채널의 고급 기능을 바로 확인할 수 있습니다.</p></div><h2 id="다음-단계-안내" tabindex="-1">다음 단계 안내 <a class="header-anchor" href="#다음-단계-안내" aria-label="Permalink to &quot;다음 단계 안내&quot;">​</a></h2><p>이 장의 학습을 완료한 후 다음을 계속 탐색할 수 있습니다:</p><ul><li><strong><a href="./../advanced/models-auth/">AI 모델 및 인증 구성</a></strong> - 다양한 AI 모델 제공업체 구성</li><li><strong><a href="./../advanced/session-management/">세션 관리 및 다중 Agent</a></strong> - 세션 격리 및 하위 Agent 협업 학습</li><li><strong><a href="./../advanced/tools-browser/">도구 시스템</a></strong> - 브라우저 자동화, 명령 실행 등 도구 사용</li></ul><h2 id="자주-묻는-질문" tabindex="-1">자주 묻는 질문 <a class="header-anchor" href="#자주-묻는-질문" aria-label="Permalink to &quot;자주 묻는 질문&quot;">​</a></h2><details class="details custom-block"><summary>여러 채널을 동시에 사용할 수 있나요?</summary><p>네! Clawdbot은 동시에 여러 채널을 활성화하는 것을 지원합니다. 다른 채널에서 메시지를 수신하고 보낼 수 있으며 모든 메시지는 통합된 Gateway를 통해 처리됩니다.</p></details><details class="details custom-block"><summary>어떤 채널을 가장 추천하나요?</summary><p>사용 시나리오에 따라 다릅니다:</p><ul><li><strong>WebChat</strong> - 가장 간단하며 구성이 필요 없음</li><li><strong>WhatsApp</strong> - 친구 및 가족과 채팅하기에 적합</li><li><strong>Telegram</strong> - Bot API가 안정적이며 자동 응답에 적합</li><li><strong>Slack/Discord</strong> - 팀 협업에 적합</li></ul></details><details class="details custom-block"><summary>채널 구성에 비용이 드나요?</summary><p>대부분의 채널은 무료이지만 일부 채널에는 비용이 발생할 수 있습니다:</p><ul><li>WhatsApp Business API - 비용이 발생할 수 있음</li><li>Google Chat - Google Workspace 계정 필요</li><li>기타 채널 - 일반적으로 무료이며 Bot Token만 신청하면 됨</li></ul></details>',33)])])}const p=o(r,[["render",i]]);export{m as __pageData,p as default};
